17578                                          StableRdxVal2, "op.rdx", ReductionOps);
17579               ExtraReds[I / 2] = std::make_pair(InstVals[I].first, ExtraRed);
17580             }
17581             if (Sz % 2 == 1)
17582               ExtraReds[Sz / 2] = InstVals.back();
17583             return ExtraReds;
17584           };
