15857 /// Checks if the quadratic mean deviation is less than 90% of the mean size.
15858 static bool checkTreeSizes(ArrayRef<std::pair<unsigned, unsigned>> Sizes,
15859                            bool First) {
15860   unsigned Num = 0;
15861   uint64_t Sum = std::accumulate(
15862       Sizes.begin(), Sizes.end(), static_cast<uint64_t>(0),
15863       [&](uint64_t V, const std::pair<unsigned, unsigned> &Val) {
15864         unsigned Size = First ? Val.first : Val.second;
15865         if (Size == 1)
15866           return V;
15867         ++Num;
15868         return V + Size;
15869       });
15870   if (Num == 0)
15871     return true;
15872   uint64_t Mean = Sum / Num;
15873   if (Mean == 0)
15874     return true;
15875   uint64_t Dev = std::accumulate(
15876                      Sizes.begin(), Sizes.end(), static_cast<uint64_t>(0),
15877                      [&](uint64_t V, const std::pair<unsigned, unsigned> &Val) {
15878                        unsigned P = First ? Val.first : Val.second;
15879                        if (P == 1)
15880                          return V;
15881                        return V + (P - Mean) * (P - Mean);
15882                      }) /
15883                  Num;
15884   return Dev * 81 / (Mean * Mean) == 0;
15885 }
