4149   }
4150   SmallVector<int> MaskOrder;
4151   if (Order.empty()) {
4152     MaskOrder.resize(Sz);
4153     std::iota(MaskOrder.begin(), MaskOrder.end(), 0);
4154   } else {
4155     inversePermutation(Order, MaskOrder);
4156   }
4157   reorderReuses(MaskOrder, Mask);
