14218 void BoUpSLP::optimizeGatherSequence() {
14219   LLVM_DEBUG(dbgs() << "SLP: Optimizing " << GatherShuffleExtractSeq.size()
14220                     << " gather sequences instructions.\n");
14221   // LICM InsertElementInst sequences.
14222   for (Instruction *I : GatherShuffleExtractSeq) {
14223     if (isDeleted(I))
14224       continue;
14225 
14226     // Check if this block is inside a loop.
14227     Loop *L = LI->getLoopFor(I->getParent());
14228     if (!L)
14229       continue;
14230 
14231     // Check if it has a preheader.
14232     BasicBlock *PreHeader = L->getLoopPreheader();
14233     if (!PreHeader)
14234       continue;
14235 
14236     // If the vector or the element that we insert into it are
14237     // instructions that are defined in this basic block then we can't
14238     // hoist this instruction.
14239     if (any_of(I->operands(), [L](Value *V) {
14240           auto *OpI = dyn_cast<Instruction>(V);
14241           return OpI && L->contains(OpI);
14242         }))
14243       continue;
14244 
14245     // We can hoist this instruction. Move it to the pre-header.
14246     I->moveBefore(PreHeader->getTerminator());
14247     CSEBlocks.insert(PreHeader);
14248   }
14249 
14250   // Make a list of all reachable blocks in our CSE queue.
14251   SmallVector<const DomTreeNode *, 8> CSEWorkList;
14252   CSEWorkList.reserve(CSEBlocks.size());
14253   for (BasicBlock *BB : CSEBlocks)
14254     if (DomTreeNode *N = DT->getNode(BB)) {
14255       assert(DT->isReachableFromEntry(N));
14256       CSEWorkList.push_back(N);
14257     }
14258 
14259   // Sort blocks by domination. This ensures we visit a block after all blocks
14260   // dominating it are visited.
14261   llvm::sort(CSEWorkList, [](const DomTreeNode *A, const DomTreeNode *B) {
14262     assert((A == B) == (A->getDFSNumIn() == B->getDFSNumIn()) &&
14263            "Different nodes should have different DFS numbers");
14264     return A->getDFSNumIn() < B->getDFSNumIn();
14265   });
14266 
14267   // Less defined shuffles can be replaced by the more defined copies.
14268   // Between two shuffles one is less defined if it has the same vector operands
14269   // and its mask indeces are the same as in the first one or undefs. E.g.
14270   // shuffle %0, poison, <0, 0, 0, undef> is less defined than shuffle %0,
14271   // poison, <0, 0, 0, 0>.
14272   auto &&IsIdenticalOrLessDefined = [this](Instruction *I1, Instruction *I2,
14273                                            SmallVectorImpl<int> &NewMask) {
14274     if (I1->getType() != I2->getType())
14275       return false;
14276     auto *SI1 = dyn_cast<ShuffleVectorInst>(I1);
14277     auto *SI2 = dyn_cast<ShuffleVectorInst>(I2);
14278     if (!SI1 || !SI2)
14279       return I1->isIdenticalTo(I2);
14280     if (SI1->isIdenticalTo(SI2))
14281       return true;
14282     for (int I = 0, E = SI1->getNumOperands(); I < E; ++I)
14283       if (SI1->getOperand(I) != SI2->getOperand(I))
14284         return false;
14285     // Check if the second instruction is more defined than the first one.
14286     NewMask.assign(SI2->getShuffleMask().begin(), SI2->getShuffleMask().end());
14287     ArrayRef<int> SM1 = SI1->getShuffleMask();
14288     // Count trailing undefs in the mask to check the final number of used
14289     // registers.
14290     unsigned LastUndefsCnt = 0;
14291     for (int I = 0, E = NewMask.size(); I < E; ++I) {
14292       if (SM1[I] == PoisonMaskElem)
14293         ++LastUndefsCnt;
14294       else
14295         LastUndefsCnt = 0;
14296       if (NewMask[I] != PoisonMaskElem && SM1[I] != PoisonMaskElem &&
14297           NewMask[I] != SM1[I])
14298         return false;
14299       if (NewMask[I] == PoisonMaskElem)
14300         NewMask[I] = SM1[I];
14301     }
14302     // Check if the last undefs actually change the final number of used vector
14303     // registers.
14304     return SM1.size() - LastUndefsCnt > 1 &&
14305            TTI->getNumberOfParts(SI1->getType()) ==
14306                TTI->getNumberOfParts(
14307                    FixedVectorType::get(SI1->getType()->getElementType(),
14308                                         SM1.size() - LastUndefsCnt));
14309   };
14310   // Perform O(N^2) search over the gather/shuffle sequences and merge identical
14311   // instructions. TODO: We can further optimize this scan if we split the
14312   // instructions into different buckets based on the insert lane.
14313   SmallVector<Instruction *, 16> Visited;
14314   for (auto I = CSEWorkList.begin(), E = CSEWorkList.end(); I != E; ++I) {
14315     assert(*I &&
14316            (I == CSEWorkList.begin() || !DT->dominates(*I, *std::prev(I))) &&
14317            "Worklist not sorted properly!");
14318     BasicBlock *BB = (*I)->getBlock();
14319     // For all instructions in blocks containing gather sequences:
14320     for (Instruction &In : llvm::make_early_inc_range(*BB)) {
14321       if (isDeleted(&In))
14322         continue;
14323       if (!isa<InsertElementInst, ExtractElementInst, ShuffleVectorInst>(&In) &&
14324           !GatherShuffleExtractSeq.contains(&In))
14325         continue;
14326 
14327       // Check if we can replace this instruction with any of the
14328       // visited instructions.
14329       bool Replaced = false;
14330       for (Instruction *&V : Visited) {
14331         SmallVector<int> NewMask;
14332         if (IsIdenticalOrLessDefined(&In, V, NewMask) &&
14333             DT->dominates(V->getParent(), In.getParent())) {
14334           In.replaceAllUsesWith(V);
14335           eraseInstruction(&In);
14336           if (auto *SI = dyn_cast<ShuffleVectorInst>(V))
14337             if (!NewMask.empty())
14338               SI->setShuffleMask(NewMask);
14339           Replaced = true;
14340           break;
14341         }
14342         if (isa<ShuffleVectorInst>(In) && isa<ShuffleVectorInst>(V) &&
14343             GatherShuffleExtractSeq.contains(V) &&
14344             IsIdenticalOrLessDefined(V, &In, NewMask) &&
14345             DT->dominates(In.getParent(), V->getParent())) {
14346           In.moveAfter(V);
14347           V->replaceAllUsesWith(&In);
14348           eraseInstruction(V);
14349           if (auto *SI = dyn_cast<ShuffleVectorInst>(&In))
14350             if (!NewMask.empty())
14351               SI->setShuffleMask(NewMask);
14352           V = &In;
14353           Replaced = true;
14354           break;
14355         }
14356       }
14357       if (!Replaced) {
14358         assert(!is_contained(Visited, &In));
14359         Visited.push_back(&In);
14360       }
14361     }
14362   }
14363   CSEBlocks.clear();
14364   GatherShuffleExtractSeq.clear();
14365 }
